---播放黑幕遮罩

---@class LBattleSkillActFadeExtraTop
local LBattleSkillActFadeExtraTop = classX("LBattleSkillActFadeExtraTop", nil)

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActFadeExtraTop.Execute(player,effData, playState, callback)
    local fade = player:GetFadeObj()

    local _viewMgr = player:GetViewMgr()

    local para =
    {
        parentRoot = _viewMgr:GetFadeRoot(),
        startTime = _viewMgr:GetTime(),
        playTime = effData.playTime, --光效持续时间
        dissipateTime = effData.dissipateTime, --光效消散时间
        alpha = tonumber(effData.playNum),
        layer = "EffectUp",
        order = 29,
        type = LBattleFadeType.TYPE_TWO,
    }

    fade:Initialize(para)
end

return LBattleSkillActFadeExtraTop